// Private sub-widgets for BTPagination.
// NOT exported from the public barrel.

import 'package:btech_tokens/btech_tokens.dart';
import 'package:flutter/material.dart';
import 'package:flutter_svg/flutter_svg.dart';

// ── Icon helpers ─────────────────────────────────────────────────────────────

/// All icons are Figma-exported SVG assets, not Material Icons.
/// Each icon has an enabled and disabled variant so callers can pass the
/// appropriate one to BTButton without needing an extra ColorFiltered wrapper.
class PaginationIcons {
  static Widget chevronLeft(BTColorTheme c) => SvgPicture.asset(
        'packages/btech_assets/assets/icons/pagination/chevron_left.svg',
        width: 16,
        height: 16,
        colorFilter: ColorFilter.mode(c.text.primary, BlendMode.srcIn),
      );

  static Widget chevronLeftDisabled(BTColorTheme c) => SvgPicture.asset(
        'packages/btech_assets/assets/icons/pagination/chevron_left.svg',
        width: 16,
        height: 16,
        colorFilter: ColorFilter.mode(c.text.disabled, BlendMode.srcIn),
      );

  static Widget chevronRight(BTColorTheme c) => SvgPicture.asset(
        'packages/btech_assets/assets/icons/pagination/chevron_right.svg',
        width: 16,
        height: 16,
        colorFilter: ColorFilter.mode(c.text.primary, BlendMode.srcIn),
      );

  static Widget chevronRightDisabled(BTColorTheme c) => SvgPicture.asset(
        'packages/btech_assets/assets/icons/pagination/chevron_right.svg',
        width: 16,
        height: 16,
        colorFilter: ColorFilter.mode(c.text.disabled, BlendMode.srcIn),
      );

  /// Chevron-down used by the rows-per-page trigger — no disabled variant
  /// (trigger is never disabled).
  static Widget chevronDown(BTColorTheme c) => SvgPicture.asset(
        'packages/btech_assets/assets/icons/pagination/chevron_down.svg',
        width: 16,
        height: 16,
        colorFilter: ColorFilter.mode(c.text.primary, BlendMode.srcIn),
      );

  /// Figma-exported first_page icon — vertical bar + chevron-left.
  static Widget firstPage(BTColorTheme c) => SvgPicture.asset(
        'packages/btech_assets/assets/icons/pagination/first_page.svg',
        width: 16,
        height: 16,
        colorFilter: ColorFilter.mode(c.text.primary, BlendMode.srcIn),
      );

  static Widget firstPageDisabled(BTColorTheme c) => SvgPicture.asset(
        'packages/btech_assets/assets/icons/pagination/first_page.svg',
        width: 16,
        height: 16,
        colorFilter: ColorFilter.mode(c.text.disabled, BlendMode.srcIn),
      );

  /// Figma-exported last_page icon — chevron-right + vertical bar.
  static Widget lastPage(BTColorTheme c) => SvgPicture.asset(
        'packages/btech_assets/assets/icons/pagination/last_page.svg',
        width: 16,
        height: 16,
        colorFilter: ColorFilter.mode(c.text.primary, BlendMode.srcIn),
      );

  static Widget lastPageDisabled(BTColorTheme c) => SvgPicture.asset(
        'packages/btech_assets/assets/icons/pagination/last_page.svg',
        width: 16,
        height: 16,
        colorFilter: ColorFilter.mode(c.text.disabled, BlendMode.srcIn),
      );
}

// ── Nav group row ────────────────────────────────────────────────────────────

/// Thin Row wrapper for a group of nav buttons.
/// PaginationNavBtn and PaginationRowsTrigger have been replaced by BTButton
/// at the call site in pagination.widget.dart (CLAUDE.md §13).
class PaginationNavGroup extends StatelessWidget {
  const PaginationNavGroup({required this.children, super.key});

  final List<Widget> children;

  @override
  Widget build(BuildContext context) {
    return Row(mainAxisSize: MainAxisSize.min, children: children);
  }
}

/// BTPagination — data pagination molecule.
/// Figma: node 749-2846.
///
/// Three named constructors match the three design variants:
///
/// ## Usage — number:
/// ```dart
/// BTPagination.number(
///   currentPage: _page,
///   totalPages: 20,
///   onPageChange: (p) => setState(() => _page = p),
/// )
/// ```
///
/// Use [maxVisiblePills] to control how many page pills are visible.
/// Defaults to `3` (compact / mobile) — pass `7` for full desktop view.
/// A `LayoutBuilder` will still clamp down automatically for narrow screens
/// even when `maxVisiblePills` is set higher.
///
/// ```dart
/// BTPagination.number(
///   currentPage: _page,
///   totalPages: 20,
///   maxVisiblePills: 7,   // desktop / wider screens
///   onPageChange: (p) => setState(() => _page = p),
/// )
/// ```
///
/// ## Usage — display:
/// ```dart
/// BTPagination.display(
///   currentPage: _page,
///   totalPages: 14,
///   totalCount: 137,
///   rowsPerPage: _rows,
///   onPageChange: (p) => setState(() => _page = p),
///   onRowsChange: (r) => setState(() => _rows = r),
/// )
/// ```
///
/// ## Usage — step:
/// ```dart
/// BTPagination.step(
///   currentStep: _step,
///   totalSteps: 5,
///   onPrev: () => setState(() => _step--),
///   onNext: () => setState(() => _step++),
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../button/button.types.dart';
import '../button/button.widget.dart';
import '../dropdown-list/dropdown_list.types.dart';
import '../dropdown/dropdown.widget.dart';
import 'package:btech_ui/src/components/molecules/pagination/internal/pagination.widgets.dart';
import 'package:btech_ui/src/components/molecules/pagination/pagination.types.dart';
import '../step-number/step_number.widget.dart';
import 'package:flutter/material.dart';

/// Data pagination molecule — see file header for usage.
class BTPagination extends StatelessWidget {
  const BTPagination._({
    required BTPaginationVariant variant,
    this.currentPage = 1,
    this.totalPages = 1,
    this.totalCount,
    this.rowsPerPage = 10,
    this.rowsPerPageOptions = const [10, 20, 50],
    this.currentStep = 1,
    this.totalSteps = 1,
    this.maxVisiblePills = 3,
    this.onPageChange,
    this.onRowsChange,
    this.onPrev,
    this.onNext,
    super.key,
  }) : _variant = variant;

  /// Full numbered pagination — first/prev/pages/next/last.
  ///
  /// [maxVisiblePills] controls how many page pills show by default.
  /// Defaults to `3` (compact/mobile). Pass `7` for full desktop view.
  /// The LayoutBuilder will further clamp down on narrow screens.
  factory BTPagination.number({
    required int currentPage,
    required int totalPages,
    required ValueChanged<int> onPageChange,
    int maxVisiblePills = 3,
    Key? key,
  }) =>
      BTPagination._(
        variant: BTPaginationVariant.number,
        currentPage: currentPage,
        totalPages: totalPages,
        maxVisiblePills: maxVisiblePills,
        onPageChange: onPageChange,
        key: key,
      );

  /// Rows-per-page dropdown (BTDropdown) + prev/next.
  factory BTPagination.display({
    required int currentPage,
    required int totalPages,
    required int totalCount,
    required ValueChanged<int> onPageChange,
    int rowsPerPage = 10,
    List<int> rowsPerPageOptions = const [10, 20, 50],
    ValueChanged<int>? onRowsChange,
    Key? key,
  }) =>
      BTPagination._(
        variant: BTPaginationVariant.display,
        currentPage: currentPage,
        totalPages: totalPages,
        totalCount: totalCount,
        rowsPerPage: rowsPerPage,
        rowsPerPageOptions: rowsPerPageOptions,
        onPageChange: onPageChange,
        onRowsChange: onRowsChange,
        key: key,
      );

  /// Step N of M + Prev / Next (BTButton secondaryLight, 16px gap).
  factory BTPagination.step({
    required int currentStep,
    required int totalSteps,
    required VoidCallback onPrev,
    required VoidCallback onNext,
    Key? key,
  }) =>
      BTPagination._(
        variant: BTPaginationVariant.step,
        currentStep: currentStep,
        totalSteps: totalSteps,
        onPrev: onPrev,
        onNext: onNext,
        key: key,
      );

  final BTPaginationVariant _variant;
  final int currentPage;
  final int totalPages;
  final int? totalCount;
  final int rowsPerPage;
  final List<int> rowsPerPageOptions;
  final int currentStep;
  final int totalSteps;

  /// Maximum page pills to show in the number variant before
  /// compressing to ellipsis. Defaults to `3` (compact/mobile).
  final int maxVisiblePills;

  final ValueChanged<int>? onPageChange;
  final ValueChanged<int>? onRowsChange;
  final VoidCallback? onPrev;
  final VoidCallback? onNext;

  bool get _isFirstPage => currentPage <= 1;
  bool get _isLastPage  => currentPage >= totalPages;

  /// Builds the visible page list for the number variant.
  ///
  /// -1 signals an ellipsis slot.
  /// [maxPills] controls how many slots are rendered — adjusted responsively.
  List<int> _buildVisiblePages({required int maxPills}) {
    if (totalPages <= maxPills) {
      return List.generate(totalPages, (i) => i + 1);
    }

    if (maxPills <= 3) {
      // Minimal compact view: prev | current | next
      if (currentPage <= 1) return [1, 2, -1];
      if (currentPage >= totalPages) return [-1, totalPages - 1, totalPages];
      return [-1, currentPage, -1];
    }

    if (maxPills <= 5) {
      // Compact view — 5 slots
      if (currentPage <= 2) return [1, 2, -1, totalPages - 1, totalPages];
      if (currentPage >= totalPages - 1) {
        return [1, 2, -1, totalPages - 1, totalPages];
      }
      return [1, -1, currentPage, -1, totalPages];
    }

    // Standard 7-slot windowing
    if (currentPage <= 4) return [1, 2, 3, 4, 5, -1, totalPages];
    if (currentPage >= totalPages - 3) {
      return [
        1, -1,
        totalPages - 4, totalPages - 3, totalPages - 2,
        totalPages - 1, totalPages,
      ];
    }
    return [
      1, -1, currentPage - 1, currentPage, currentPage + 1, -1, totalPages,
    ];
  }

  void _goTo(int page) {
    if (page < 1 || page > totalPages || page == currentPage) return;
    onPageChange?.call(page);
  }

  @override
  Widget build(BuildContext context) {
    switch (_variant) {
      case BTPaginationVariant.number:
        return _buildNumber(context);
      case BTPaginationVariant.display:
        return _buildDisplay(context);
      case BTPaginationVariant.step:
        return _buildStep(context);
    }
  }

  // ── number ───────────────────────────────────────────────────────────────

  Widget _buildNumber(BuildContext context) {
    final c = context.btColor;

    return LayoutBuilder(
      builder: (ctx, constraints) {
        // Each pill = 32px + 8px gap = 40px.
        // Reserve ~200px for the two nav groups.
        final pagesWidth =
            (constraints.maxWidth - 200).clamp(40.0, double.infinity);
        final rawPills   = (pagesWidth / 40).floor().clamp(3, 7);
        // Ensure odd for symmetric ellipsis; also respect maxVisiblePills.
        final computed   = rawPills.isOdd ? rawPills : rawPills - 1;
        final effectiveMax =
            computed < maxVisiblePills ? computed : maxVisiblePills;
        // Always use at least 3 pills
        final cappedMax  = effectiveMax < 3 ? 3 : effectiveMax;

        final pages = _buildVisiblePages(maxPills: cappedMax);

        return Row(
          children: [
            // Left nav
            PaginationNavGroup(children: [
              Tooltip(
                message: 'First page',
                child: BTButton.iconOnly(
                  icon: _isFirstPage
                      ? PaginationIcons.firstPageDisabled(c)
                      : PaginationIcons.firstPage(c),
                  variant: BTButtonVariant.ghost,
                  size: BTButtonSize.sm,
                  onPressed: _isFirstPage ? null : () => _goTo(1),
                ),
              ),
              BTButton(
                label: 'Previous',
                leftIcon: _isFirstPage
                    ? PaginationIcons.chevronLeftDisabled(c)
                    : PaginationIcons.chevronLeft(c),
                variant: BTButtonVariant.ghost,
                size: BTButtonSize.sm,
                onPressed: _isFirstPage ? null : () => _goTo(currentPage - 1),
              ),
            ],),

            // Center pages
            Expanded(
              child: Wrap(
                alignment: WrapAlignment.center,
                spacing: 8,
                runSpacing: 8,
                children: pages.map((p) {
                  if (p == -1) {
                    return BTStepNumber.ellipsis(colors: c);
                  }
                  return BTStepNumber(
                    page: p,
                    isActive: p == currentPage,
                    onTap: () => _goTo(p),
                    colors: c,
                  );
                }).toList(),
              ),
            ),

            // Right nav
            PaginationNavGroup(children: [
              BTButton(
                label: 'Next',
                rightIcon: _isLastPage
                    ? PaginationIcons.chevronRightDisabled(c)
                    : PaginationIcons.chevronRight(c),
                variant: BTButtonVariant.ghost,
                size: BTButtonSize.sm,
                onPressed: _isLastPage ? null : () => _goTo(currentPage + 1),
              ),
              Tooltip(
                message: 'Last page',
                child: BTButton.iconOnly(
                  icon: _isLastPage
                      ? PaginationIcons.lastPageDisabled(c)
                      : PaginationIcons.lastPage(c),
                  variant: BTButtonVariant.ghost,
                  size: BTButtonSize.sm,
                  onPressed: _isLastPage ? null : () => _goTo(totalPages),
                ),
              ),
            ],),
          ],
        );
      },
    );
  }

  // ── display ──────────────────────────────────────────────────────────────

  Widget _buildDisplay(BuildContext context) {
    final c = context.btColor;

    final dropdownItems = rowsPerPageOptions
        .map(
          (opt) => BTDropdownItem<int>(
            value: opt,
            label: '$opt',
            checked: opt == rowsPerPage,
          ),
        )
        .toList();

    return Row(
      mainAxisAlignment: MainAxisAlignment.spaceBetween,
      children: [
        // Left: rows-per-page selector
        Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            Text(
              'Rows per page',
              style: TextStyle(
                fontSize: 14.0,
                fontWeight: FontWeight.w500,
                color: c.text.secondary,
              ),
            ),
            SizedBox(width: 8.0),
            BTDropdown<int>(
              items: dropdownItems,
              value: rowsPerPage,
              onSelect: (v) => onRowsChange?.call(v),
              // secondaryWhite trigger; isOpen drives AnimatedRotation (180°).
              trigger: ({required toggle, required isOpen}) => BTButton(
                label: '$rowsPerPage',
                rightIcon: AnimatedRotation(
                  turns: isOpen ? 0.5 : 0.0,
                  duration: const Duration(milliseconds: 150),
                  child: PaginationIcons.chevronDown(c),
                ),
                variant: BTButtonVariant.secondaryWhite,
                size: BTButtonSize.sm,
                onPressed: toggle,
              ),
            ),
          ],
        ),

        // Right: prev / next
        PaginationNavGroup(children: [
          BTButton(
            label: 'Previous',
            leftIcon: _isFirstPage
                ? PaginationIcons.chevronLeftDisabled(c)
                : PaginationIcons.chevronLeft(c),
            variant: BTButtonVariant.ghost,
            size: BTButtonSize.sm,
            onPressed: _isFirstPage ? null : () => _goTo(currentPage - 1),
          ),
          BTButton(
            label: 'Next',
            rightIcon: _isLastPage
                ? PaginationIcons.chevronRightDisabled(c)
                : PaginationIcons.chevronRight(c),
            variant: BTButtonVariant.ghost,
            size: BTButtonSize.sm,
            onPressed: _isLastPage ? null : () => _goTo(currentPage + 1),
          ),
        ],),
      ],
    );
  }

  // ── step ─────────────────────────────────────────────────────────────────

  Widget _buildStep(BuildContext context) {
    final c = context.btColor;

    return Row(
      mainAxisAlignment: MainAxisAlignment.spaceBetween,
      children: [
        // Step label
        Text(
          'Step $currentStep of $totalSteps',
          style: TextStyle(
            fontSize: 14.0,
            fontWeight: FontWeight.w500,
            color: c.text.primary,
          ),
        ),

        // Prev / Next — BTButton secondaryLight, 16px gap between them
        Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            BTButton(
              label: 'Prev',
              variant: BTButtonVariant.secondaryLight,
              size: BTButtonSize.sm,
              onPressed: currentStep <= 1 ? null : onPrev,
            ),
            SizedBox(width: 16.0),
            BTButton(
              label: 'Next',
              variant: BTButtonVariant.secondaryLight,
              size: BTButtonSize.sm,
              onPressed: currentStep >= totalSteps ? null : onNext,
            ),
          ],
        ),
      ],
    );
  }
}
